import{c as a,Q as t,j as r,m as i}from"./chunks/framework.D9IbVcwA.js";const u=JSON.parse('{"title":"034-process-fork-exec-3 · Fork 与 Exec","description":"","frontmatter":{"title":"034-process-fork-exec-3 · Fork 与 Exec"},"headers":[],"relativePath":"tutorial/034-process-fork-exec-3.md","filePath":"tutorial/034-process-fork-exec-3.md","lastUpdated":1779686691000}'),o={name:"tutorial/034-process-fork-exec-3.md"};function l(n,e,p,s,d,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="execve-与进程生命周期管理" tabindex="-1">execve 与进程生命周期管理 <a class="header-anchor" href="#execve-与进程生命周期管理" aria-label="Permalink to &quot;execve 与进程生命周期管理&quot;">​</a></h1><blockquote><p>标签：execve, ELF loading, waitpid, zombie, process lifecycle 前置：tag 034-2 fork 的艺术</p></blockquote><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>上一篇我们让 fork 跑起来了——子进程和父进程共享物理页，标记 CoW，通过 trampoline 从 fork 调用点返回 0。但子进程现在只能跑和父进程一样的代码，这不是我们想要的。</p><p>真正的多进程世界里，fork 之后紧跟的是 execve——用一个全新的程序替换当前进程的内存映像。execve 是进程生命周期中&quot;替换&quot;操作的核心，waitpid 是&quot;回收&quot;操作的核心。加上 fork 的&quot;创建&quot;，三者构成了完整的进程生命周期：创建 -&gt; 运行（可能被 execve 替换）-&gt; 退出 -&gt; 回收。</p><p>这一篇我们打通整条链路。</p><h2 id="环境说明" tabindex="-1">环境说明 <a class="header-anchor" href="#环境说明" aria-label="Permalink to &quot;环境说明&quot;">​</a></h2><p>execve 从 ext2 文件系统（AHCI port 1）读取 ELF 文件。构建脚本自动把 user/shell 复制到 ext2 镜像的 /bin/sh。QEMU 启动参数包含 <code>-drive file=ext2.img,format=raw</code> 挂载 ext2 镜像。</p><p>这个 tag 的大部分代码在 <code>kernel/proc/process.cpp</code> 中，包括 execve()、waitpid()、clear_user_mappings()、以及 elf_error_to_execve() 辅助函数。系统调用注册在 <code>kernel/syscall/sys_execve.cpp</code> 和 <code>kernel/syscall/sys_waitpid.cpp</code> 中。</p><h2 id="execve-的完整链路" tabindex="-1">execve 的完整链路 <a class="header-anchor" href="#execve-的完整链路" aria-label="Permalink to &quot;execve 的完整链路&quot;">​</a></h2><p>execve 做的事情用一句话概括：把当前进程的地址空间清空，从文件系统读取一个新的 ELF 可执行文件，把 PT_LOAD 段映射到地址空间，然后把入口点地址写入 task-&gt;ctx.rip。</p><h3 id="路径解析" tabindex="-1">路径解析 <a class="header-anchor" href="#路径解析" aria-label="Permalink to &quot;路径解析&quot;">​</a></h3><p>先说路径解析。execve 接收一个路径字符串（比如 &quot;/bin/sh&quot;），首先做参数检查——路径不能是空指针也不能是空字符串。</p><p>然后通过 vfs_resolve 解析到具体的文件系统实例和相对路径（&quot;bin/sh&quot;），再用 fs-&gt;lookup 找到 inode。接下来检查 inode 的类型——必须是 Regular 文件，不能是目录。</p><p>任何一步失败都返回对应的 errno 风格错误码（ENOENT=-2, EISDIR=-21 等）。ExecveResult 枚举把每个错误都映射到了 Linux 标准的 errno 值，这样 syscall 层可以直接返回给用户态。</p><h3 id="elf-读取与防御性检查" tabindex="-1">ELF 读取与防御性检查 <a class="header-anchor" href="#elf-读取与防御性检查" aria-label="Permalink to &quot;ELF 读取与防御性检查&quot;">​</a></h3><p>然后是 ELF 读取。先检查 inode-&gt;size &gt;= sizeof(Elf64_Ehdr)（64 字节），太小就返回 ReadFailed。</p><p>然后检查 inode-&gt;ops 是否为 nullptr——如果文件系统驱动没有实现 read 操作，直接返回错误。这些防御性检查看起来很琐碎，但在内核开发中，任何一步的疏忽都可能导致 null pointer dereference 然后收获一个漂亮的 kernel panic。</p><p>用栈上的 64 字节缓冲区读取 ELF header，validate_elf_header 验证后提取 program header table 的位置和数量。用 aligned new 动态分配缓冲区一次性读取所有 program headers。验证阶段已经确认了 phoff、phentsize、phnum 都是合法的，所以读取可以放心进行。用完记得 delete[] phdrs——忘记释放会导致内核堆内存泄漏。</p><h3 id="清除旧映射" tabindex="-1">清除旧映射 <a class="header-anchor" href="#清除旧映射" aria-label="Permalink to &quot;清除旧映射&quot;">​</a></h3><p>接下来是关键步骤——清除旧映射。</p><p>clear_user_mappings 做四层嵌套遍历（PML4 -&gt; PDPT -&gt; PD -&gt; PT），释放所有用户空间的物理页——不只是数据页，页表页本身（PT、PD、PDPT 页）也都逐一释放，所有 entry 清零。</p><p>这一步彻底摧毁了旧的地址空间，为新程序腾出位置。内存释放的顺序是从叶子到根：先释放 PT 级别的数据页，然后释放 PT 页表页，再释放 PD 页表页，最后释放 PDPT 页表页。这个顺序确保了在释放子节点之前不会丢失对它的引用。</p><h2 id="pt-load-段加载" tabindex="-1">PT_LOAD 段加载 <a class="header-anchor" href="#pt-load-段加载" aria-label="Permalink to &quot;PT_LOAD 段加载&quot;">​</a></h2><p>最后是 PT_LOAD 段加载。对每个 PT_LOAD 段，计算它覆盖的虚拟地址范围（seg_start = p_vaddr 向下对齐到页，seg_end = p_vaddr + p_memsz 向上对齐到页），逐页处理：分配物理页、清零、从 ELF 文件填充数据、map 到地址空间。</p><h3 id="页内偏移计算" tabindex="-1">页内偏移计算 <a class="header-anchor" href="#页内偏移计算" aria-label="Permalink to &quot;页内偏移计算&quot;">​</a></h3><p>实际代码使用 <code>page_base_offset = vaddr - p_vaddr</code> 来判断当前页是否有文件数据需要读取。</p><p>如果 page_base_offset &lt; p_filesz，说明这一页还有文件数据没读完，计算 copy_len（从当前偏移到 filesz 结束，不超过一页大小），从文件的 p_offset + copy_start 位置读取数据写入物理页的 copy_start 位置。</p><p>这个算法的前提是 ELF 的 PT_LOAD 段的 p_vaddr 是页对齐的（p_align 通常为 0x1000），所以 seg_start 等于 p_vaddr，page_base_offset 从 0 开始递增。如果 p_vaddr 不是页对齐的，需要额外的页内偏移处理——需要区分 in_page_off（数据在页内的起始位置）和 seg_offset（段内偏移，用于文件读取位置）。不过 Cinux 的 shell 和标准工具都是页对齐的 ELF，所以当前实现足够使用。</p><h3 id="bss-清零" tabindex="-1">BSS 清零 <a class="header-anchor" href="#bss-清零" aria-label="Permalink to &quot;BSS 清零&quot;">​</a></h3><p>每页在填充文件数据之前先清零，这样 memsz &gt; filesz 的部分（.bss 段）自然就是零，不需要额外的清零步骤。这是一个巧妙的设计决策——先清零整页，再填入文件数据，BSS 自然就是零。</p><h3 id="段标志位转换" tabindex="-1">段标志位转换 <a class="header-anchor" href="#段标志位转换" aria-label="Permalink to &quot;段标志位转换&quot;">​</a></h3><p>段标志位也需要转换：根据 PF_W 设置 FLAG_WRITABLE，根据 PF_X 清除 FLAG_NX（No-Execute）。代码段通常是 PF_R | PF_X（只读可执行），数据段是 PF_R | PF_W（可读写）。</p><h3 id="入口点设置" tabindex="-1">入口点设置 <a class="header-anchor" href="#入口点设置" aria-label="Permalink to &quot;入口点设置&quot;">​</a></h3><p>加载完成后检查 has_load_segment 标志——如果没有找到任何 PT_LOAD 段就返回 NoLoadSegments。</p><p>最后设置 task-&gt;ctx.rip = ehdr-&gt;e_entry，返回 Ok。注意 PID、ppid、parent、children 等进程身份信息保持不变——execve 只替换内存映像，不改变进程身份。这是 POSIX 标准的核心语义。</p><h3 id="与-linux-的对比" tabindex="-1">与 Linux 的对比 <a class="header-anchor" href="#与-linux-的对比" aria-label="Permalink to &quot;与 Linux 的对比&quot;">​</a></h3><p>Linux 的 load_elf_binary 处理了更复杂的情况——包括 PT_LOAD 的 p_align 要求（可能 0x200000 对齐大页）、ELF 随机化（ASLR）、以及 memsz &gt; filesz 的 BSS 清零。Cinux 的简化版本先清零整页再填入文件数据，BSS 自然就是零。</p><h2 id="waitpid-与-zombie-回收" tabindex="-1">waitpid 与 Zombie 回收 <a class="header-anchor" href="#waitpid-与-zombie-回收" aria-label="Permalink to &quot;waitpid 与 Zombie 回收&quot;">​</a></h2><p>进程调用 exit() 后进入 Zombie 状态——TCB 还在内存里（父进程可能要读取 exit_status），但不再参与调度。</p><p>父进程调用 waitpid 收集子进程的退出状态、从 children 链表 unlink、释放 PID、把子进程标记为 Dead。</p><h3 id="非阻塞设计" tabindex="-1">非阻塞设计 <a class="header-anchor" href="#非阻塞设计" aria-label="Permalink to &quot;非阻塞设计&quot;">​</a></h3><p>Cinux 的 waitpid 是非阻塞的——如果子进程还没退出就返回 NotExited。</p><p>这在 cooperative scheduler 中是合理的：阻塞等待需要&quot;唤醒&quot;机制（子进程 exit 时通知父进程），增加了不少复杂度。调用者可以用循环重试来模拟阻塞效果（Terminal 析构函数就这么做——在循环中反复调用 waitpid，直到子进程变成 Zombie 被回收）。</p><h3 id="链表遍历与-unlink" tabindex="-1">链表遍历与 unlink <a class="header-anchor" href="#链表遍历与-unlink" aria-label="Permalink to &quot;链表遍历与 unlink&quot;">​</a></h3><p>waitpid 的实现扫描父进程的 children 单链表，支持两种模式：pid &gt; 0 时等待指定子进程，pid == -1 时等待任意一个退出的子进程。</p><p>遍历时维护 prev 指针用于 unlink 操作——如果 prev 是 nullptr 说明目标是头节点，要把 parent-&gt;children 改为 target-&gt;wait_next。</p><p>找到 Zombie 状态的子进程后，收集 exit_status、从链表 unlink、释放 PID（通过 pid_alloc.free）、标记 Dead。每一步都有清晰的日志输出，方便调试。</p><h3 id="与-linux-的对比-1" tabindex="-1">与 Linux 的对比 <a class="header-anchor" href="#与-linux-的对比-1" aria-label="Permalink to &quot;与 Linux 的对比&quot;">​</a></h3><p>Linux 的 waitpid（实际是 waitid 系统调用）默认阻塞，通过 wait_queue 实现——子进程 exit 时调用 wake_up_process 唤醒等待的父进程。WNOHANG 标志可以变成非阻塞模式。</p><p>xv6 的 wait 也是阻塞的，在 sleep 系统调用上等待（xv6 用 sleep/wakeup 原语替代条件变量）。</p><h2 id="进程状态机" tabindex="-1">进程状态机 <a class="header-anchor" href="#进程状态机" aria-label="Permalink to &quot;进程状态机&quot;">​</a></h2><p>Cinux 的进程有五个状态：</p><ul><li><strong>Ready</strong>：刚创建或刚被唤醒，等待调度</li><li><strong>Running</strong>：正在 CPU 上跑</li><li><strong>Blocked</strong>：等待 I/O 或锁（比如 pipe 空时 sys_read 阻塞）</li><li><strong>Zombie</strong>：已退出但父进程还没 waitpid</li><li><strong>Dead</strong>：已被回收，TCB 可释放</li></ul><p>状态转换路径：TaskBuilder.build() 创建时 Ready -&gt; Scheduler 调度时 Running -&gt; 等 I/O 时 Blocked -&gt; I/O 完成时 Ready -&gt; exit() 时 Zombie -&gt; 父进程 waitpid 时 Dead。</p><p>fork 出来的子进程直接是 Ready（不是 Running——它需要等调度器选中）。这个状态机看起来简单，但它覆盖了 Cinux 目前所有进程的完整生命周期。</p><h3 id="与其他内核的对比" tabindex="-1">与其他内核的对比 <a class="header-anchor" href="#与其他内核的对比" aria-label="Permalink to &quot;与其他内核的对比&quot;">​</a></h3><p>这个状态机和 xv6 非常接近——xv6 也有 UNUSED/EMBRYO/RUNNABLE/RUNNING/ZOMBIE 五个状态（多了 UNUSED 和 EMBRYO 用于 TCB 分配过程）。</p><p>Linux 更复杂——有 TASK_INTERRUPTIBLE/TASK_UNINTERRUPTIBLE/TASK_STOPPED/TASK_TRACED 等细分状态。</p><h2 id="收尾" tabindex="-1">收尾 <a class="header-anchor" href="#收尾" aria-label="Permalink to &quot;收尾&quot;">​</a></h2><p>到这里 tag 034 的三个核心组件全部就位：ELF 解析、fork with CoW、execve + waitpid。内核现在具备了完整的多进程创建和执行能力。</p><p>后续我们会把这些能力用到实际场景中——让 Shell 从 ext2 独立加载，让桌面支持多终端并发。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Linux do_execve: <a href="https://github.com/torvalds/linux/blob/master/fs/exec.c" target="_blank" rel="noreferrer">https://github.com/torvalds/linux/blob/master/fs/exec.c</a></li><li>Linux load_elf_binary: <a href="https://github.com/torvalds/linux/blob/master/fs/binfmt_elf.c" target="_blank" rel="noreferrer">https://github.com/torvalds/linux/blob/master/fs/binfmt_elf.c</a></li><li>xv6 exec.c: <a href="https://github.com/mit-pdos/xv6-riscv/blob/riscv/kernel/exec.c" target="_blank" rel="noreferrer">https://github.com/mit-pdos/xv6-riscv/blob/riscv/kernel/exec.c</a></li><li>POSIX waitpid: <a href="https://pubs.opengroup.org/onlinepubs/9699919799/functions/waitpid.html" target="_blank" rel="noreferrer">https://pubs.opengroup.org/onlinepubs/9699919799/functions/waitpid.html</a></li><li>Intel SDM Vol.3A Section 6.15 &quot;Page-Fault Exception (#PF)&quot;</li></ul>',64)])])}const x=a(o,[["render",l]]);export{u as __pageData,x as default};
